import './index.css';

import {
  useState
} from 'react';

import {
  addMarks
} from '../../services/marksService';

function AddMarksPage() {

  const [formData, setFormData] =
    useState({

      student_id: '',
      subject_id: '',
      assessment_id: '',
      marks_obtained: ''

    });

  const handleChange =
    (e) => {

    setFormData({

      ...formData,

      [e.target.name]:
      e.target.value

    });

  };

  const handleSubmit =
    async (e) => {

    e.preventDefault();

    try {

      await addMarks(formData);

      alert(
        'Marks Added Successfully'
      );

    } catch (error) {

      console.log(error);

      alert(
        error.response?.data?.message
      );

    }

  };

  return (

    <div className="page">

      <h1>
        Add Marks
      </h1>

      <form
        className="form"
        onSubmit={handleSubmit}
      >

        <input
          type="number"
          name="student_id"
          placeholder="Student ID"
          onChange={handleChange}
        />

        <input
          type="number"
          name="subject_id"
          placeholder="Subject ID"
          onChange={handleChange}
        />

        <input
          type="number"
          name="assessment_id"
          placeholder="Assessment ID"
          onChange={handleChange}
        />

        <input
          type="number"
          name="marks_obtained"
          placeholder="Marks"
          onChange={handleChange}
        />

        <button type="submit">

          Add Marks

        </button>

      </form>

    </div>

  );

}

export default AddMarksPage;
